        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
        .padding({ left: 32, right: 32, bottom: 32 })
      }
      .width('100%')
      .height('100%')
      .borderRadius(28)
      .backgroundColor('#FFFFFF')
      .clip(true)
      .shadow({ radius: 60, color: 'rgba(30,41,59,0.09)', offsetX: 0, offsetY: 24 })
      // Front visible when not flipped.
      .opacity(this.flipped ? 0 : 1)

      // ---- Back face (meaning + phonetic) ----
      Column() {
        Row()
          .width('100%')
          .height(8)
          .linearGradient({
            angle: 90,
            colors: [['#0D9488', 0.0], ['#0EA5E9', 1.0]],
          })

        // Meaning section.
        Column() {
          Text('中文释义')
            .fontSize(12)
            .fontWeight(FontWeight.Bold)
            .fontColor('#94A3B8')
            .margin({ bottom: 10 })
          Text(this.meaning)
            .fontSize(34)
            .fontWeight(FontWeight.Bold)
            .fontColor('#0F172A')
            .textAlign(TextAlign.Center)
            .maxLines(4)
            .textOverflow({ overflow: TextOverflow.Ellipsis })
        }
        .layoutWeight(1)
        .width('100%')
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)

        // Divider.
        Divider()
          .color('#F1F5F9')
          .strokeWidth(1)
          .margin({ left: 28, right: 28 })

        // Phonetic section.
        Column() {
          Text('音标')
            .fontSize(12)
            .fontWeight(FontWeight.Bold)
            .fontColor('#94A3B8')
            .margin({ bottom: 10 })
          Text(this.phonetic.length > 0 ? this.phonetic : '—')
            .fontSize(20)
            .fontWeight(FontWeight.Normal)
            .fontColor('#475569')
            .textAlign(TextAlign.Center)
        }
        .layoutWeight(1)
        .width('100%')
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
      }
      .width('100%')
      .height('100%')
      .borderRadius(28)
      .backgroundColor('#FFFFFF')
      .clip(true)
      .shadow({ radius: 60, color: 'rgba(30,41,59,0.09)', offsetX: 0, offsetY: 24 })
      // Pre-rotate back 180° around Y so it reads upright once the card finishes turning.
      .rotate({ y: 1, angle: 180 })
      // Back visible when flipped.
      .opacity(this.flipped ? 1 : 0)
    }
    .width(this.cardWidth)
    .height(this.cardHeight)
    .rotate({ y: 1, angle: this.flipped ? 180 : 0 })
    .animation({ duration: this.flipDuration, curve: Curve.EaseInOut })
    .onClick(() => this.onFlip())
    .id('review-flashcard')
  }
}
